private float startX, startY;
private boolean isDragging = false;

view.setOnTouchListener(new View.OnTouchListener() {
 @Override
 public boolean onTouch(View v, MotionEvent event) {
 switch (event.getAction()) {
 case MotionEvent.ACTION_DOWN:
 startX = event.getRawX();
 startY = event.getRawY();
 isDragging = true;
 return true; // Consume event

 case MotionEvent.ACTION_MOVE:
 if (isDragging) {
 float deltaX = event.getRawX() - startX;
 float deltaY = event.getRawY() - startY;
 v.setTranslationX(v.getTranslationX() + deltaX);
 v.setTranslationY(v.getTranslationY() + deltaY);
 startX = event.getRawX();
 startY = event.getRawY();
 }
 return true;

 case MotionEvent.ACTION_UP:
 case MotionEvent.ACTION_CANCEL:
 isDragging = false;
 return true;
 }
 return false;
 }
});

GestureDetector.SimpleOnGestureListener listener = 
 new GestureDetector.SimpleOnGestureListener() {

 private static final int SWIPE_THRESHOLD = 100;
 private static final int SWIPE_VELOCITY_THRESHOLD = 100;

 @Override
 public boolean onFling(MotionEvent e1, MotionEvent e2, 
 float velocityX, float velocityY) {
 float diffX = e2.getX() - e1.getX();
 float diffY = e2.getY() - e1.getY();

 if (Math.abs(diffX) > Math.abs(diffY) &&
 Math.abs(diffX) > SWIPE_THRESHOLD &&
 Math.abs(velocityX) > SWIPE_VELOCITY_THRESHOLD) {

 if (diffX > 0) {
 // Swipe RIGHT
 Toast.makeText(context, "Swipe Right!", Toast.LENGTH_SHORT).show();
 } else {
 // Swipe LEFT
 Toast.makeText(context, "Swipe Left!", Toast.LENGTH_SHORT).show();
 }
 return true;
 }
 return false;
 }
};

GestureDetector detector = new GestureDetector(context, listener);

// In activity or view
@Override
public boolean onTouchEvent(MotionEvent event) {
 return detector.onTouchEvent(event) || super.onTouchEvent(event);
}
